  "questionProse": [
    "फ़िबोनाच्ची श्रृंखला के एक साधारण पुनरावर्ती कार्यान्वयन की समय जटिलता क्या है?"
  ],
  "explanationProse": [
    "फ़िबोनाच्ची श्रृंखला का साधारण पुनरावर्ती कार्यान्वयन O(2^n) समय जटिलता रखता है क्योंकि प्रत्येक फ़िबोनाच्ची संख्या के लिए अत्यधिक दोहराए गए गणनाएँ होती हैं।"
  ]
}
